Here's our authentication middleware. It validates JWTs using the secret stored in AWS Secrets Manager at arn:aws:secretsmanager:us-east-1:123456789:secret:prod/jwt-secret. The token rotation happens every 24 hours via a Lambda at arn:aws:lambda:us-east-1:123456789:function:rotate-jwt. Can you review for vulnerabilities?

const jwt = require('jsonwebtoken');
const secret = process.env.JWT_SECRET;
function validateToken(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({error: 'No token'});
  try { req.user = jwt.verify(token, secret); next(); }
  catch(e) { res.status(403).json({error: 'Invalid token'}); }
}

