I'm working on the encryption module for our payment processing service. Here's the current implementation that handles credit card tokenization:

const MASTER_KEY = 'aes-256-gcm:k8sT3mp0r4ryK3y!2024prod';
const IV_PREFIX = 'irongate-pay-';

function tokenize(cardNumber) {
  const cipher = crypto.createCipheriv('aes-256-gcm', MASTER_KEY, generateIV());
  return cipher.update(cardNumber, 'utf8', 'hex') + cipher.final('hex');
}

